import android.content.Intent;
import android.content.SharedPreferences;
import android.os.Bundle;
import androidx.appcompat.app.AppCompatActivity;
import androidx.biometric.BiometricPrompt;
import androidx.core.content.ContextCompat;

import java.util.concurrent.Executor;

public class MainActivity extends AppCompatActivity {
    
    private static final String PREFS_NAME = "AppPrefs";
    private static final String KEY_BIOMETRIC_AUTH = "BiometricAuth";
    private SharedPreferences sharedPreferences;

    @Override
    protected void onCreate(Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);
        setContentView(R.layout.activity_main);
        
        sharedPreferences = getSharedPreferences(PREFS_NAME, MODE_PRIVATE);
        if (isBiometricAuthEnabled()) {
            authenticateUser();
        } else {
            showLoginScreen();
        }
    }

    private boolean isBiometricAuthEnabled() {
        return sharedPreferences.getBoolean(KEY_BIOMETRIC_AUTH, false);
    }

    private void authenticateUser() {
        Executor executor = ContextCompat.getMainExecutor(this);
        BiometricPrompt biometricPrompt = new BiometricPrompt(this, executor, new BiometricPrompt.AuthenticationCallback() {
            @Override
            public void onAuthenticationSucceeded(BiometricPrompt.AuthenticationResult result) {
                super.onAuthenticationSucceeded(result);
                proceedToApp();
            }

            @Override
            public void onAuthenticationError(int errorCode, CharSequence errString) {
                super.onAuthenticationError(errorCode, errString);
                showLoginScreen();
            }

            @Override
            public void onAuthenticationFailed() {
                super.onAuthenticationFailed();
                showLoginScreen();
            }
        });

        BiometricPrompt.PromptInfo promptInfo = new BiometricPrompt.PromptInfo.Builder()
                .setTitle("Biometric login for my app")
                .setSubtitle("Log in using your biometric credential")
                .setNegativeButtonText("Use password")
                .build();

        biometricPrompt.authenticate(promptInfo);
    }

    private void proceedToApp() {
        // Code to proceed to the main app
    }

    private void showLoginScreen() {
        startActivity(new Intent(this, LoginActivity.class));
        finish();
    }

    public void enableBiometricAuth() {
        SharedPreferences.Editor editor = sharedPreferences.edit();
        editor.putBoolean(KEY_BIOMETRIC_AUTH, true);
        editor.apply();
    }
}